import{_ as t,c as a,o as i,ag as o}from"./chunks/framework.Bzez9NG9.js";const m=JSON.parse('{"title":"SPACE","titleTemplate":"Terms of Service","description":"","frontmatter":{"title":"SPACE","titleTemplate":"Terms of Service"},"headers":[],"relativePath":"terms.md","filePath":"terms.md"}'),s={name:"terms.md"};function r(n,e,c,l,u,d){return i(),a("div",null,e[0]||(e[0]=[o('<h1 id="terms-of-service" tabindex="-1">Terms of Service <a class="header-anchor" href="#terms-of-service" aria-label="Permalink to &quot;Terms of Service&quot;">​</a></h1><p><em>Last updated: May 2026</em></p><p>These Terms of Service (&quot;Terms&quot;) govern your access to and use of <strong>Succeedium Planning Analytics Cloud Extension (SPACE)</strong>, our extension and related application for IBM Planning Analytics / TM1 provided by <strong>Succeedium</strong> (&quot;Succeedium&quot;, &quot;we&quot;, &quot;us&quot;, or &quot;our&quot;).</p><p>Please read these Terms carefully before installing, accessing, or using SPACE.</p><p>By installing, accessing, or using SPACE, you agree to be bound by these Terms. If you are using SPACE on behalf of an organization, you represent that you have authority to bind that organization to these Terms. If you do not agree to these Terms, you may not install, access, or use SPACE.</p><p>Please also review our <a href="https://succeedium.com/space/privacy" target="_blank" rel="noreferrer">Privacy Policy</a>, which explains how we handle information in connection with SPACE.</p><h2 id="_1-scope-of-these-terms" tabindex="-1">1. Scope of These Terms <a class="header-anchor" href="#_1-scope-of-these-terms" aria-label="Permalink to &quot;1. Scope of These Terms&quot;">​</a></h2><p>These Terms apply to SPACE, including the SPACE browser extension, web application, server components, documentation, support services, licensing systems, and any related services we provide.</p><p>These Terms do not apply to third-party products or services that are not owned or controlled by Succeedium, including IBM Planning Analytics, IBM Planning Analytics Workspace, IBM Cloud, customer-hosted environments, cloud infrastructure providers, browser providers, or other third-party platforms used by your organization.</p><p>If you or your organization has entered into a separate written agreement, order form, statement of work, data processing agreement, service level agreement, or other written agreement with Succeedium, that agreement may contain additional or different terms. If there is a conflict between these Terms and a separately signed or accepted agreement with Succeedium, the separately signed or accepted agreement will control to the extent of the conflict.</p><h2 id="_2-description-of-space" tabindex="-1">2. Description of SPACE <a class="header-anchor" href="#_2-description-of-space" aria-label="Permalink to &quot;2. Description of SPACE&quot;">​</a></h2><p>SPACE provides additional functionality for IBM Planning Analytics / TM1, including features that may be accessed through IBM Planning Analytics Workspace, a browser extension, a web application, server components, or related integrations.</p><p>Depending on the features enabled and your organization’s configuration, SPACE may include functionality for model documentation, lifecycle management, model comparison, deployment, log access, log search, troubleshooting, Python and Jupyter integration, scripting, automation, administration, AI-assisted features, and other IBM Planning Analytics / TM1-related capabilities.</p><p>SPACE may allow authorized users to read, analyze, document, compare, deploy, modify, automate, or otherwise work with IBM Planning Analytics / TM1 metadata, data, logs, scripts, configuration, and related information.</p><p>You are responsible for how SPACE is configured and used within your organization, including connections, permissions, scripts, automations, deployments, model changes, log retention, AI features, and other actions performed through SPACE.</p><h2 id="_3-accounts-access-and-permissions" tabindex="-1">3. Accounts, Access, and Permissions <a class="header-anchor" href="#_3-accounts-access-and-permissions" aria-label="Permalink to &quot;3. Accounts, Access, and Permissions&quot;">​</a></h2><p>To use SPACE, you may need:</p><ul><li>access to IBM Planning Analytics / TM1;</li><li>access to IBM Planning Analytics Workspace or other supported IBM Planning Analytics interfaces;</li><li>authorization to install or use the SPACE browser extension, web application, or server components;</li><li>appropriate IBM Planning Analytics permissions;</li><li>appropriate SPACE roles, permissions, and connection access;</li><li>a valid SPACE license, subscription, trial, or other authorization.</li></ul><p>SPACE may process authentication and authorization information, including IBM Planning Analytics session information, tokens, cookies, credentials, or other authentication-related information, depending on the authentication method and configuration used.</p><p>You are responsible for ensuring that you have the required authority and permissions to use SPACE with your IBM Planning Analytics / TM1 environments and any related systems.</p><h2 id="_4-customer-responsibilities" tabindex="-1">4. Customer Responsibilities <a class="header-anchor" href="#_4-customer-responsibilities" aria-label="Permalink to &quot;4. Customer Responsibilities&quot;">​</a></h2><p>You and your organization are responsible for:</p><ul><li>managing IBM Planning Analytics users, roles, groups, permissions, and access controls;</li><li>managing SPACE users, roles, permissions, connections, and feature access;</li><li>ensuring only authorized users access SPACE;</li><li>ensuring users are trained and authorized to use SPACE features;</li><li>determining which IBM Planning Analytics / TM1 environments, models, logs, scripts, files, and other information are made available to SPACE;</li><li>reviewing model documentation, comparisons, deployments, scripts, automations, log analysis, AI-generated outputs, and other results before relying on them;</li><li>maintaining backups and recovery processes for business-critical systems, models, scripts, and data;</li><li>testing lifecycle, deployment, automation, writeback, administrative, and script-based actions before using them in production environments;</li><li>ensuring your use of SPACE complies with applicable laws, regulations, internal policies, and contractual obligations;</li><li>ensuring that any information submitted to SPACE, support channels, or AI-assisted features is authorized by your organization.</li></ul><p>SPACE may allow users to access logs, run scripts, execute automations, modify model objects, deploy changes, generate documentation, use AI-assisted features, or perform administrative actions. You are responsible for the outcome of actions performed through SPACE, including any changes to IBM Planning Analytics / TM1 environments, model objects, logs, scripts, data, configuration, permissions, or related systems.</p><h2 id="_5-subscription-orders-and-payment" tabindex="-1">5. Subscription, Orders, and Payment <a class="header-anchor" href="#_5-subscription-orders-and-payment" aria-label="Permalink to &quot;5. Subscription, Orders, and Payment&quot;">​</a></h2><p>SPACE is generally provided as an online, subscription-based product.</p><p>Subscription terms, fees, renewal terms, number of users, support level, payment terms, discounts, trials, evaluation periods, deployment model, hosting model, and other commercial terms may be set out in an applicable order form, invoice, quote, purchase order, statement of work, or other written agreement between you and Succeedium.</p><p>Unless otherwise stated in an applicable written agreement, all fees are non-refundable and payable in accordance with the applicable order or invoice.</p><p>If payment is overdue, or if your use of SPACE exceeds the scope of your license or subscription, Succeedium may suspend or limit access to SPACE after providing reasonable notice, unless immediate suspension is required for security, legal, or operational reasons.</p><h2 id="_6-changes-to-space" tabindex="-1">6. Changes to SPACE <a class="header-anchor" href="#_6-changes-to-space" aria-label="Permalink to &quot;6. Changes to SPACE&quot;">​</a></h2><p>SPACE is an online product, and we may update, improve, modify, add, or discontinue features from time to time.</p><p>We make changes to SPACE to improve performance, security, usability, reliability, compatibility, and compliance; to respond to customer feedback and product needs; and to address changes in IBM Planning Analytics, IBM Planning Analytics Workspace, IBM Cloud, APIs, browsers, security requirements, customer environments, or applicable law.</p><p>We aim to improve SPACE over time and avoid changes that materially reduce the value of existing paid subscriptions. Subject to our obligations under applicable orders or written agreements, we may modify or discontinue features where reasonably necessary for product development, security, reliability, compliance, third-party platform compatibility, or customer needs.</p><p>Where a change materially affects existing paid subscriptions, we will use commercially reasonable efforts to provide reasonable notice.</p><h2 id="_7-customer-data-and-processing" tabindex="-1">7. Customer Data and Processing <a class="header-anchor" href="#_7-customer-data-and-processing" aria-label="Permalink to &quot;7. Customer Data and Processing&quot;">​</a></h2><p>SPACE processes information as needed to provide the functionality requested by the customer or authorized users.</p><p>Depending on how SPACE is configured and used, SPACE may process user information, authentication information, IBM Planning Analytics connection information, IBM Planning Analytics metadata, IBM Planning Analytics data, logs, scripts, files, documentation, support information, technical logs, diagnostics, and other information described in our <a href="https://succeedium.com/space/privacy" target="_blank" rel="noreferrer">Privacy Policy</a>.</p><p>SPACE does not sell customer data.</p><p>Depending on customer configuration and enabled features, SPACE may store certain IBM Planning Analytics / TM1 metadata, logs, documentation, scripts, files, configuration information, AI interaction history, or other customer-authorized information in SPACE databases or customer-controlled infrastructure.</p><p>You are responsible for ensuring that your use of SPACE, including any data submitted to or processed through SPACE, is authorized by your organization and complies with applicable laws, internal policies, and agreements.</p><h2 id="_8-ibm-planning-analytics-tm1-access-and-actions" tabindex="-1">8. IBM Planning Analytics / TM1 Access and Actions <a class="header-anchor" href="#_8-ibm-planning-analytics-tm1-access-and-actions" aria-label="Permalink to &quot;8. IBM Planning Analytics / TM1 Access and Actions&quot;">​</a></h2><p>SPACE connects to IBM Planning Analytics / TM1 environments using customer-authorized access.</p><p>Depending on configuration and permissions, SPACE may allow authorized users to:</p><ul><li>read IBM Planning Analytics / TM1 metadata, data, logs, and configuration;</li><li>generate or update model documentation;</li><li>compare model objects and environments;</li><li>create releases or deployment packages;</li><li>deploy model objects or changes between environments;</li><li>search, index, store, or analyze logs;</li><li>run, schedule, or manage scripts, notebooks, tasks, or automations;</li><li>use AI-assisted features with customer-authorized model context;</li><li>perform administrative or support-related actions.</li></ul><p>You are responsible for reviewing and validating any actions performed through SPACE before using them in production or business-critical environments.</p><p>Succeedium is not responsible for loss, damage, errors, downtime, incorrect deployments, data changes, model changes, permission changes, script behavior, automation behavior, or other outcomes caused by customer instructions, customer configurations, user actions, IBM Planning Analytics permissions, or third-party systems.</p><h2 id="_9-python-jupyter-scripts-and-automation" tabindex="-1">9. Python, Jupyter, Scripts, and Automation <a class="header-anchor" href="#_9-python-jupyter-scripts-and-automation" aria-label="Permalink to &quot;9. Python, Jupyter, Scripts, and Automation&quot;">​</a></h2><p>SPACE may include Python, Jupyter, scripting, scheduling, or automation features.</p><p>Scripts, notebooks, automations, uploaded files, generated files, scheduled tasks, and related outputs are customer-controlled materials. Customers and users are responsible for reviewing, testing, securing, and approving such materials before use.</p><p>Scripts and automations may access IBM Planning Analytics / TM1 environments, customer systems, files, APIs, credentials, or other resources depending on customer configuration and permissions.</p><p>You are responsible for ensuring that scripts, notebooks, uploaded files, scheduled tasks, and automation workflows comply with your organization’s internal policies, security requirements, and applicable laws.</p><p>Succeedium is not responsible for actions, errors, data changes, security issues, service interruptions, or other outcomes caused by customer-created scripts, notebooks, automations, uploaded files, scheduled tasks, or execution instructions.</p><h2 id="_10-ai-assisted-features" tabindex="-1">10. AI-Assisted Features <a class="header-anchor" href="#_10-ai-assisted-features" aria-label="Permalink to &quot;10. AI-Assisted Features&quot;">​</a></h2><p>SPACE may include optional AI-assisted features.</p><h3 id="_10-1-space-ai-assistant" tabindex="-1">10.1 SPACE AI Assistant <a class="header-anchor" href="#_10-1-space-ai-assistant" aria-label="Permalink to &quot;10.1 SPACE AI Assistant&quot;">​</a></h3><p>SPACE AI Assistant is designed to provide model-aware AI assistance for IBM Planning Analytics / TM1 environments where the customer has purchased, configured, and enabled the feature.</p><p>Depending on customer configuration and user permissions, SPACE AI Assistant may process customer-authorized IBM Planning Analytics / TM1 context, including model metadata, cube structures, dimensions, hierarchies, elements, subsets, views, attributes, rules, processes, chores, logs, report definitions, formulas, scripts, documentation, and other information made available by the customer or its authorized users.</p><p>SPACE AI Assistant may use this context to help users understand models, generate documentation, analyze dependencies, troubleshoot errors, explain rules or processes, review logs, suggest improvements, assist with reporting, or support other model-aware use cases.</p><p>Customers control whether SPACE AI Assistant is enabled and which authorized users or roles may access it, where such controls are supported.</p><h3 id="_10-2-teamone-space-integration" tabindex="-1">10.2 TeamOne + SPACE Integration <a class="header-anchor" href="#_10-2-teamone-space-integration" aria-label="Permalink to &quot;10.2 TeamOne + SPACE Integration&quot;">​</a></h3><p>Customers who separately use TeamOne and SPACE may have access to AI-assisted functionality through an integration between TeamOne and SPACE.</p><p>Where such integration is enabled, TeamOne may surface SPACE AI Assistant capabilities or use SPACE-authorized context to provide model-aware assistance. Such model-aware functionality is separate from general TeamOne AI Help and is available only where SPACE has been purchased, configured, and enabled by the customer.</p><h3 id="_10-3-customer-controlled-and-private-ai-environments" tabindex="-1">10.3 Customer-Controlled and Private AI Environments <a class="header-anchor" href="#_10-3-customer-controlled-and-private-ai-environments" aria-label="Permalink to &quot;10.3 Customer-Controlled and Private AI Environments&quot;">​</a></h3><p>Where supported, customers may configure SPACE AI Assistant to use a customer-controlled or private AI environment, such as a private cloud AI service, enterprise AI deployment, private GPT-style environment, or customer-managed AI provider.</p><p>In such cases, prompts, model context, metadata, logs, scripts, and generated outputs may be processed within the customer-selected AI environment, subject to the customer’s configuration, agreements, security controls, and provider terms.</p><p>This configuration may help customers align AI processing with their internal security, privacy, data residency, vendor-management, and compliance requirements.</p><h3 id="_10-4-ai-outputs" tabindex="-1">10.4 AI Outputs <a class="header-anchor" href="#_10-4-ai-outputs" aria-label="Permalink to &quot;10.4 AI Outputs&quot;">​</a></h3><p>AI-assisted features are provided for convenience and assistance only. AI-generated outputs may be inaccurate, incomplete, outdated, or inappropriate for your specific use case.</p><p>You are responsible for reviewing and validating any AI-generated suggestions, formulas, reports, explanations, documentation, code, scripts, configuration guidance, troubleshooting steps, model analysis, log analysis, deployment guidance, or other outputs before relying on them.</p><p>AI-generated outputs should not be treated as professional, financial, legal, tax, accounting, security, or compliance advice. You remain responsible for decisions made using SPACE, TeamOne, IBM Planning Analytics, scripts, automations, AI-assisted features, or any related systems.</p><h3 id="_10-5-ai-data-use" tabindex="-1">10.5 AI Data Use <a class="header-anchor" href="#_10-5-ai-data-use" aria-label="Permalink to &quot;10.5 AI Data Use&quot;">​</a></h3><p>We do not sell customer data.</p><p>We do not use customer content submitted through SPACE or TeamOne AI-assisted features to train public or general-purpose AI models unless expressly agreed in writing.</p><p>AI-assisted features may use Succeedium-managed AI providers, third-party AI service providers, or customer-configured AI providers, including private or customer-controlled AI environments where supported. The data exposure and processing model may depend on the AI configuration selected by the customer.</p><p>Customers are responsible for reviewing and approving the AI configuration appropriate for their organization and ensuring users are authorized to submit information to AI-assisted features.</p><h2 id="_11-third-party-services" tabindex="-1">11. Third-Party Services <a class="header-anchor" href="#_11-third-party-services" aria-label="Permalink to &quot;11. Third-Party Services&quot;">​</a></h2><p>SPACE interoperates with third-party platforms, including IBM Planning Analytics, IBM Planning Analytics Workspace, IBM Cloud, browsers, cloud infrastructure providers, AI providers, and other services used or configured by you, your organization, or Succeedium.</p><p>Succeedium does not control and is not responsible for third-party products or services, including their availability, performance, security, privacy practices, API changes, service limitations, outages, errors, terms, or decisions.</p><p>Your use of third-party products and services is subject to the applicable third-party terms, policies, agreements, and configurations.</p><p>Succeedium is not responsible for loss, damage, delay, outage, error, or inability to use SPACE caused by third-party products or services, customer systems, network issues, misconfiguration, lack of permissions, browser behavior, or changes to third-party APIs or platforms.</p><h2 id="_12-acceptable-use" tabindex="-1">12. Acceptable Use <a class="header-anchor" href="#_12-acceptable-use" aria-label="Permalink to &quot;12. Acceptable Use&quot;">​</a></h2><p>You may not use SPACE to:</p><ul><li>violate any applicable law, regulation, or third-party right;</li><li>access, process, or disclose information without authorization;</li><li>bypass, disable, or interfere with security, licensing, access control, or usage limits;</li><li>reverse engineer, decompile, disassemble, copy, modify, or create derivative works of SPACE except as permitted by law;</li><li>interfere with or disrupt SPACE, Succeedium systems, IBM systems, customer systems, or other third-party systems;</li><li>introduce viruses, malware, harmful code, or malicious content;</li><li>perform unauthorized security testing, scanning, scraping, or automated access;</li><li>abuse APIs, overload systems, or circumvent rate limits;</li><li>use scripts, notebooks, automations, or AI-assisted features in a way that could compromise security, availability, confidentiality, integrity, or compliance;</li><li>use SPACE to send spam, phishing, fraudulent, misleading, or unlawful content;</li><li>use SPACE in a way that could damage, disable, overburden, or impair the service or related systems.</li></ul><p>Succeedium may investigate suspected violations of this section and may suspend or limit access where reasonably necessary to protect the service, customers, users, or third parties.</p><h2 id="_13-suspension-and-termination" tabindex="-1">13. Suspension and Termination <a class="header-anchor" href="#_13-suspension-and-termination" aria-label="Permalink to &quot;13. Suspension and Termination&quot;">​</a></h2><p>Succeedium may suspend or terminate access to SPACE if:</p><ul><li>you violate these Terms or another applicable agreement;</li><li>payment is overdue;</li><li>your subscription expires or is not renewed;</li><li>your use exceeds the scope of your license or subscription;</li><li>your use creates a security, legal, operational, or reputational risk;</li><li>suspension is required by law, court order, third-party platform requirement, or governmental authority;</li><li>continued access could harm Succeedium, customers, users, third parties, or related systems.</li></ul><p>Where reasonable under the circumstances, Succeedium will provide notice before suspension or termination. However, Succeedium may suspend access immediately where necessary to address security, legal, operational, or abuse-related risks.</p><p>Upon termination or expiration of your subscription, your right to access and use SPACE will end, unless otherwise agreed in writing.</p><h2 id="_14-intellectual-property" tabindex="-1">14. Intellectual Property <a class="header-anchor" href="#_14-intellectual-property" aria-label="Permalink to &quot;14. Intellectual Property&quot;">​</a></h2><p>SPACE, including its software, code, design, user interface, documentation, workflows, features, trademarks, logos, content, and related materials, is owned by Succeedium or its licensors and is protected by applicable intellectual property laws.</p><p>Subject to these Terms and any applicable order or written agreement, Succeedium grants you a limited, non-exclusive, non-transferable, non-sublicensable, revocable right to use SPACE during the applicable subscription, trial, or authorized use period.</p><p>You do not acquire any ownership rights in SPACE.</p><p>You retain ownership of your data, IBM Planning Analytics content, reports, scripts, notebooks, files, prompts, inputs, outputs, documentation, and other customer-provided materials, subject to the rights and permissions necessary for Succeedium to provide, secure, support, and improve SPACE.</p><h2 id="_15-feedback" tabindex="-1">15. Feedback <a class="header-anchor" href="#_15-feedback" aria-label="Permalink to &quot;15. Feedback&quot;">​</a></h2><p>If you provide suggestions, ideas, enhancement requests, recommendations, bug reports, or other feedback about SPACE, you grant Succeedium a worldwide, perpetual, irrevocable, royalty-free right to use, modify, and incorporate that feedback into SPACE or other Succeedium products and services without obligation to you.</p><h2 id="_16-confidentiality" tabindex="-1">16. Confidentiality <a class="header-anchor" href="#_16-confidentiality" aria-label="Permalink to &quot;16. Confidentiality&quot;">​</a></h2><p>In connection with SPACE, either party may receive confidential or proprietary information from the other party.</p><p>Each party agrees to use the other party’s confidential information only for purposes related to SPACE and to protect it using reasonable care. Confidential information does not include information that is publicly available, already known without confidentiality obligations, independently developed, or lawfully received from a third party without confidentiality obligations.</p><p>Succeedium may process customer information as described in these Terms, the Privacy Policy, applicable agreements, and customer instructions.</p><h2 id="_17-support" tabindex="-1">17. Support <a class="header-anchor" href="#_17-support" aria-label="Permalink to &quot;17. Support&quot;">​</a></h2><p>Succeedium may provide support for SPACE through email, help desk systems, documentation, meetings, or other support channels.</p><p>Support availability, response times, service levels, training, implementation assistance, upgrade assistance, deployment support, and dedicated support commitments may depend on your subscription plan, order form, service level agreement, or other written agreement.</p><p>Unless otherwise agreed in writing, support is provided on a commercially reasonable basis and does not guarantee resolution of every issue.</p><h2 id="_18-beta-trial-evaluation-and-preview-features" tabindex="-1">18. Beta, Trial, Evaluation, and Preview Features <a class="header-anchor" href="#_18-beta-trial-evaluation-and-preview-features" aria-label="Permalink to &quot;18. Beta, Trial, Evaluation, and Preview Features&quot;">​</a></h2><p>Succeedium may offer beta, trial, evaluation, preview, experimental, or early-access features.</p><p>Such features may be incomplete, unsupported, changed, limited, suspended, or discontinued at any time. They may contain errors or produce unexpected results.</p><p>Unless otherwise agreed in writing, beta, trial, evaluation, preview, experimental, or early-access features are provided &quot;as is&quot; and without warranties, service level commitments, or support obligations.</p><h2 id="_19-disclaimers" tabindex="-1">19. Disclaimers <a class="header-anchor" href="#_19-disclaimers" aria-label="Permalink to &quot;19. Disclaimers&quot;">​</a></h2><p>Succeedium uses commercially reasonable efforts to operate, maintain, and secure SPACE. However, except as expressly stated in a written agreement with Succeedium, SPACE is provided on an &quot;as is&quot; and &quot;as available&quot; basis.</p><p>To the maximum extent permitted by law, Succeedium disclaims all warranties, representations, and conditions, whether express, implied, statutory, or otherwise, including warranties of merchantability, fitness for a particular purpose, title, non-infringement, accuracy, availability, reliability, uninterrupted access, error-free operation, and compatibility with third-party products or services.</p><p>Succeedium does not warrant that SPACE will be uninterrupted, error-free, free of harmful components, or that all defects will be corrected.</p><p>Succeedium does not control IBM Planning Analytics, IBM Planning Analytics Workspace, IBM Cloud, customer systems, customer networks, customer configurations, browsers, AI providers, or third-party services, and is not responsible for issues caused by them.</p><p>You are responsible for verifying model documentation, comparisons, deployments, scripts, automations, logs, AI-generated outputs, recommendations, configuration guidance, and other results before relying on them.</p><h2 id="_20-limitation-of-liability" tabindex="-1">20. Limitation of Liability <a class="header-anchor" href="#_20-limitation-of-liability" aria-label="Permalink to &quot;20. Limitation of Liability&quot;">​</a></h2><p>To the maximum extent permitted by law, Succeedium will not be liable for any indirect, incidental, special, consequential, exemplary, punitive, or similar damages, or for any loss of profits, revenue, business, goodwill, data, use, or business interruption, whether based in contract, tort, negligence, strict liability, or any other legal theory, even if Succeedium has been advised of the possibility of such damages.</p><p>To the maximum extent permitted by law, Succeedium’s total aggregate liability arising out of or relating to SPACE, these Terms, or any related services will not exceed the amounts paid by you or your organization to Succeedium for SPACE during the twelve months before the event giving rise to the claim.</p><p>The limitations in this section apply to the maximum extent permitted by law and do not limit liability that cannot legally be limited.</p><p>Certain jurisdictions do not allow certain exclusions or limitations of liability. In such jurisdictions, Succeedium’s liability will be limited to the maximum extent permitted by law.</p><h2 id="_21-indemnity" tabindex="-1">21. Indemnity <a class="header-anchor" href="#_21-indemnity" aria-label="Permalink to &quot;21. Indemnity&quot;">​</a></h2><p>You agree to defend, indemnify, and hold harmless Succeedium and its affiliates, officers, directors, employees, contractors, agents, suppliers, and licensors from and against any claims, damages, losses, liabilities, costs, and expenses, including reasonable legal fees, arising out of or relating to:</p><ul><li>your use of SPACE;</li><li>your violation of these Terms;</li><li>your violation of applicable law or third-party rights;</li><li>your data, systems, configurations, reports, scripts, notebooks, automations, prompts, inputs, outputs, deployments, model changes, or instructions;</li><li>unauthorized access, use, disclosure, or processing caused by your users, systems, credentials, permissions, configurations, scripts, automations, or instructions.</li></ul><h2 id="_22-changes-to-these-terms" tabindex="-1">22. Changes to These Terms <a class="header-anchor" href="#_22-changes-to-these-terms" aria-label="Permalink to &quot;22. Changes to These Terms&quot;">​</a></h2><p>We may update these Terms from time to time.</p><p>When we make changes, we will update the “Last updated” date at the top of this page.</p><p>If we make material changes, we will provide notice by reasonable means, which may include posting a notice on our website, providing notice through the Service, sending notice to account administrators or billing contacts, or including the change in release notes or other customer communications.</p><p>Unless otherwise stated, updated Terms become effective when posted. If a change materially affects existing paid subscriptions, we will use commercially reasonable efforts to provide advance notice before the change takes effect.</p><p>Your continued use of SPACE after the effective date of updated Terms constitutes acceptance of the updated Terms.</p><h2 id="_23-governing-law" tabindex="-1">23. Governing Law <a class="header-anchor" href="#_23-governing-law" aria-label="Permalink to &quot;23. Governing Law&quot;">​</a></h2><p>These Terms are governed by the laws of Canada and the applicable laws of the province where Succeedium is based, without regard to conflict of law principles.</p><p>The courts located in that province will have exclusive jurisdiction over disputes arising out of or relating to these Terms or SPACE, unless otherwise required by applicable law or agreed in writing.</p><h2 id="_24-contact-us" tabindex="-1">24. Contact Us <a class="header-anchor" href="#_24-contact-us" aria-label="Permalink to &quot;24. Contact Us&quot;">​</a></h2><p>If you have any questions about these Terms, please contact us at:</p><p><a href="https://succeedium.com" target="_blank" rel="noreferrer">Succeedium</a><br> Email: <a href="mailto:info@succeedium.com" target="_blank" rel="noreferrer">info@succeedium.com</a></p><hr><p><em>IBM</em>, <em>Planning Analytics</em>, and <em>TM1</em> are trademarks of International Business Machines Corporation.</p>',136)]))}const h=t(s,[["render",r]]);export{m as __pageData,h as default};
